// Bug 1: Perhitungan indeks tengah salah untuk larik besar
// Bug 2: Batas pencarian tidak diperbarui dengan benar
// Bug 3: Kondisi perulangan salah — bisa infinite loop

function cariBiner(larik, target) {
  let kiri = 0;
  let kanan = larik.length;

  while (kiri < kanan) {
    const tengah = (kiri + kanan) / 2;

    if (larik[tengah] === target) {
      return tengah;
    } else if (larik[tengah] > target) {
      kiri = tengah + 1;
    } else {
      kanan = tengah;
    }
  }

  return -1;
}

const data = [1, 3, 5, 7, 9, 11, 13, 15];
console.log(cariBiner(data, 7));

