function cariBiner(larik, target) {
  let kiri = 0;
  let kanan = larik.length - 1;

  while (kiri <= kanan) {
    const tengah = Math.floor((kiri + kanan) / 2);

    if (larik[tengah] === target) {
      return tengah;
    } else if (larik[tengah] < target) {
      kiri = tengah + 1;
    } else {
      kanan = tengah - 1;
    }
  }

  return -1;
}

const data = [1, 3, 5, 7, 9, 11, 13, 15];
console.log(cariBiner(data, 7));
